import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Helper to map condition strings to Lucide icon names or emojis
function getWeatherIcon(condition: string = '') {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return 'sun';
  if (c.includes('cloud')) return 'cloud';
  if (c.includes('rain') || c.includes('drizzle')) return 'cloud-rain';
  if (c.includes('storm') || c.includes('lightning')) return 'cloud-lightning';
  if (c.includes('snow')) return 'snowflake';
  if (c.includes('wind')) return 'wind';
  if (c.includes('fog') || c.includes('mist')) return 'cloud-fog';
  return 'cloud'; // Default icon
}

function ForecastItem(props: { day?: string; icon?: string; high?: number; low?: number; unit: string }) {
  return (
    <Box padding="var(--ggui-spacing-3)" style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 'var(--ggui-spacing-2)' }}>
      <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant)">
        {props.day?.substring(0, 3).toUpperCase()}
      </Text>
      <Icon name={getWeatherIcon(props.icon)} size={28} color="var(--ggui-color-primary-600)" />
      <Stack gap={0} align="center">
        <Text variant="bodySmall" weight="bold">
          {props.high}°
        </Text>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          {props.low}°
        </Text>
      </Stack>
    </Box>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-10)">
      <Card padding="var(--ggui-spacing-8)" shadow="lg" radius="xl">
        <Stack gap="var(--ggui-spacing-8)">
          {/* Header Section */}
          <Row justify="between" align="start">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                {new Date().toLocaleDateString(undefined, { weekday: 'long', month: 'long', day: 'numeric' })}
              </Text>
            </Stack>
            <Badge variant="primary" size="lg">{props.condition}</Badge>
          </Row>

          {/* Main Weather Content */}
          <Row align="center" justify="center" gap="var(--ggui-spacing-10)" wrap>
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Icon name={getWeatherIcon(props.condition)} size={84} color="var(--ggui-color-primary-500)" />
              <Text variant="bodyLarge" weight="semibold" color="var(--ggui-color-onSurfaceVariant)">
                {props.condition}
              </Text>
            </Stack>

            <Stack align="center" gap={0}>
              <Row align="start" gap={0}>
                <Text size="4xl" weight="bold" style={{ fontSize: 'var(--ggui-font-size-4xl)', lineHeight: 1 }}>
                  {props.temperature}
                </Text>
                <Text variant="bodyLarge" weight="bold" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
                  °{props.unit}
                </Text>
              </Row>
            </Stack>
          </Row>

          {/* Stats Bar */}
          <Card background="var(--ggui-color-surfaceVariant)" border={false} padding="var(--ggui-spacing-4)" radius="md">
            <Row justify="around" align="center">
              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="droplets" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label">Humidity</Text>
                </Row>
                <Text variant="body" weight="semibold">{props.humidity}%</Text>
              </Stack>

              <Divider orientation="vertical" margin="var(--ggui-spacing-4)" />

              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="wind" size={18} color="var(--ggui-color-primary-600)" />
                  <Text variant="label">Wind Speed</Text>
                </Row>
                <Text variant="body" weight="semibold">{props.windSpeed} km/h</Text>
              </Stack>
            </Row>
          </Card>

          {/* Forecast Section */}
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-2)" justify="between">
              {props.forecast?.map((item, idx) => (
                <ForecastItem key={idx} {...item} unit={props.unit} />
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </Container>

  );
}

