import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Helper for category color coding using design system tokens
const getCategoryColor = (category?: string) => {
  const c = category?.toLowerCase() || '';
  if (c.includes('alkali metal')) return 'var(--ggui-color-error-100)';
  if (c.includes('alkaline earth')) return 'var(--ggui-color-warning-100)';
  if (c.includes('transition metal')) return 'var(--ggui-color-primary-50)';
  if (c.includes('post-transition')) return 'var(--ggui-color-success-50)';
  if (c.includes('metalloid')) return 'var(--ggui-color-info-50)';
  if (c.includes('nonmetal')) return 'var(--ggui-color-primary-100)';
  if (c.includes('noble gas')) return 'var(--ggui-color-success-100)';
  if (c.includes('lanthanide')) return 'var(--ggui-color-info-100)';
  if (c.includes('actinide')) return 'var(--ggui-color-error-50)';
  return 'var(--ggui-color-surfaceVariant)';
};

const getCategoryTextColor = (category?: string) => {
  const c = category?.toLowerCase() || '';
  if (c.includes('alkali metal')) return 'var(--ggui-color-error-800)';
  if (c.includes('alkaline earth')) return 'var(--ggui-color-warning-800)';
  if (c.includes('transition metal')) return 'var(--ggui-color-primary-800)';
  if (c.includes('post-transition')) return 'var(--ggui-color-success-800)';
  if (c.includes('metalloid')) return 'var(--ggui-color-info-800)';
  if (c.includes('nonmetal')) return 'var(--ggui-color-primary-900)';
  if (c.includes('noble gas')) return 'var(--ggui-color-success-800)';
  if (c.includes('lanthanide')) return 'var(--ggui-color-info-800)';
  if (c.includes('actinide')) return 'var(--ggui-color-error-800)';
  return 'var(--ggui-color-onSurfaceVariant)';
};


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<typeof props.elements[0] | null>(null);

  const filteredElements = useMemo(() => {
    const query = search.toLowerCase().trim();
    const items = props.elements || [];
    if (!query) return items;
    return items.filter(el =>
      el.name?.toLowerCase().includes(query) ||
      el.symbol?.toLowerCase().includes(query)
    );
  }, [props.elements, search]);

  const categories = useMemo(() => {
    const seen = new Set<string>();
    const list: string[] = [];
    (props.elements || []).forEach(el => {
      if (el.category && !seen.has(el.category)) {
        seen.add(el.category);
        list.push(el.category);
      }
    });
    return list.sort();
  }, [props.elements]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <SearchField
            value={search}
            onChange={setSearch}
            placeholder="Search by name or symbol..."
            size="lg"
          />
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" border={false} background="var(--ggui-color-surfaceVariant)">
          <Row gap="var(--ggui-spacing-3)" wrap>
            {categories.map(cat => (
              <Row key={cat} gap="var(--ggui-spacing-1)" align="center">
                <Box
                  width="var(--ggui-spacing-3)"
                  height="var(--ggui-spacing-3)"
                  background={getCategoryColor(cat)}
                  borderRadius="var(--ggui-shape-radius-sm)"
                />
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{cat}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        {/* Periodic Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gridGap: 'var(--ggui-spacing-1)',
            minWidth: '800px',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2)'
          }}
        >
          {filteredElements.map(el => (
            <Box
              key={`${el.atomicNumber}-${el.symbol}`}
              as={Clickable}
              onClick={() => setSelected(el)}
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                aspectRatio: '1 / 1',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                background: getCategoryColor(el.category),
                color: getCategoryTextColor(el.category),
                borderRadius: 'var(--ggui-shape-radius-sm)',
                padding: 'var(--ggui-spacing-1)',
                position: 'relative',
                transition: 'transform 0.1s ease-in-out',
                outline: selected?.atomicNumber === el.atomicNumber
                  ? '2px solid var(--ggui-color-primary-600)'
                  : 'none',
                outlineOffset: '2px',
                zIndex: selected?.atomicNumber === el.atomicNumber ? 1 : 0,
              }}
              hoverStyle={{ transform: 'scale(1.05)', zIndex: 2 }}
            >
              <Text
                variant="caption"
                style={{
                  position: 'absolute',
                  top: '2px',
                  left: '2px',
                  fontSize: '9px',
                  fontWeight: 'bold'
                }}
              >
                {el.atomicNumber}
              </Text>
              <Heading level={6} style={{ marginBottom: 0 }}>{el.symbol}</Heading>
              <Text variant="caption" style={{ fontSize: '7px' }} truncate>{el.name}</Text>
            </Box>
          ))}
        </Box>

        {/* Detail Panel */}
        {selected ? (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Row gap="var(--ggui-spacing-8)" align="start" wrap>
              <Stack align="center" gap="var(--ggui-spacing-1)" style={{ minWidth: '100px' }}>
                <Box
                  padding="var(--ggui-spacing-6)"
                  background={getCategoryColor(selected.category)}
                  borderRadius="var(--ggui-shape-radius-lg)"
                  width="100px"
                  height="100px"
                  style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
                >
                  <Heading level={1} color={getCategoryTextColor(selected.category)}>{selected.symbol}</Heading>
                </Box>
                <Text variant="label">Atomic No. {selected.atomicNumber}</Text>
              </Stack>

              <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={2}>{selected.name}</Heading>
                  <Badge variant="primary" size="lg">{selected.category}</Badge>
                </Stack>
                <Divider margin="var(--ggui-spacing-2)" />
                <Row gap="var(--ggui-spacing-10)">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="bodyLarge" weight="bold">{selected.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                    <Text variant="bodyLarge" weight="bold">Row {selected.row}, Column {selected.col}</Text>
                  </Stack>
                </Row>
              </Stack>
              <Button variant="ghost" onClick={() => setSelected(null)}>Close Details</Button>
            </Row>
          </Card>
        ) : (
          <Alert variant="info" title="No element selected">
            Click an element in the table to view its full properties.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

