import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Helper to render rating stars
function RatingStars(rating: number = 0) {
  return (
    <Row gap="var(--ggui-spacing-1)">
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon
          key={star}
          name="star"
          size={16}
          color={star <= rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
        />
      ))}
    </Row>
  );
}

export default function Component(props: Props) {
  const [quantity, setQuantity] = useState(1);
  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  const handleAddToCart = () => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  };

  const specificationsData = useMemo(() => {
    return (props.product.specifications || []).map((s: any, i) => ({
      id: i.toString(),
      name: s.key || s.label || 'Feature',
      value: s.value || 'N/A',
    }));
  }, [props.product.specifications]);

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY="var(--ggui-spacing-4)">
          <Text color="var(--ggui-color-onSurfaceVariant)">{props.product.description || 'No description available.'}</Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY="var(--ggui-spacing-4)">
          <Table
            columns={[
              { key: 'name', header: 'Specification', width: '40%' },
              { key: 'value', header: 'Value' },
            ]}
            data={specificationsData}
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap="var(--ggui-spacing-4)" style={{ padding: 'var(--ggui-spacing-4) 0' }}>
          {(props.product.reviews || []).length > 0 ? (
            (props.product.reviews || []).map((review: any, i) => (
              <Card key={i} padding="var(--ggui-spacing-4)" shadow="none" border>
                <Stack gap="var(--ggui-spacing-2)">
                  <Row justify="between" align="center">
                    <Text weight="semibold">{review.author}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{review.date}</Text>
                  </Row>
                  {RatingStars(review.rating)}
                  <Text size="sm">{review.text}</Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet.</Text>
          )}
        </Stack>
      ),
    },
  ];

  const isLowStock = props.product.stock !== undefined && props.product.stock > 0 && props.product.stock <= 5;
  const isOutOfStock = props.product.stock === 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-8)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Hero/Details */}
        <Stack direction="horizontal" gap="var(--ggui-spacing-8)" wrap align="start">
          {/* Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-12)"
            style={{ flex: '1 1 400px', minHeight: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--ggui-color-outlineVariant)' }}
          >
            <Stack align="center" gap="var(--ggui-spacing-4)">
              <Icon name="image" size={64} color="var(--ggui-color-primary-300)" />
              <Heading level={3} color="var(--ggui-color-primary-700)" align="center">
                {props.product.name}
              </Heading>
            </Stack>
          </Box>

          {/* Product Details Header */}
          <Stack gap="var(--ggui-spacing-6)" style={{ flex: '1 1 300px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1}>{props.product.name}</Heading>
              <Row gap="var(--ggui-spacing-2)" align="center">
                {RatingStars(props.product.rating)}
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  ({props.product.reviewCount || 0} reviews)
                </Text>
              </Row>
            </Stack>

            <Text size="3xl" weight="bold" color="var(--ggui-color-primary-600)">
              {props.product.currency || '$'}{props.product.price?.toLocaleString()}
            </Text>

            <Box>
              {isOutOfStock ? (
                <Badge variant="error">Out of Stock</Badge>
              ) : (
                <Badge variant={isLowStock ? 'warning' : 'success'}>
                  {isLowStock ? `Low Stock: ${props.product.stock} left` : 'In Stock'}
                </Badge>
              )}
            </Box>
          </Stack>
        </Stack>

        <Divider />

        {/* Middle Section: Content Tabs */}
        <Tabs items={tabItems} variant="line" />

        {/* Bottom Section: Purchase Actions */}
        <Card padding="var(--ggui-spacing-6)" shadow="md" style={{ background: 'var(--ggui-color-surfaceVariant)' }}>
          <Stack direction="horizontal" gap="var(--ggui-spacing-6)" wrap align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label">Quantity</Text>
              <Row align="center" gap="var(--ggui-spacing-3)" style={{ background: 'var(--ggui-color-surface)', padding: 'var(--ggui-spacing-1)', borderRadius: 'var(--ggui-shape-radius-md)', border: '1px solid var(--ggui-color-outline)' }}>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setQuantity(Math.max(1, quantity - 1))}
                  disabled={isOutOfStock || quantity <= 1}
                >
                  <Icon name="minus" size={16} />
                </Button>
                <Text weight="bold" style={{ width: '40px', textAlign: 'center' }}>{quantity}</Text>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setQuantity(Math.min(props.product.stock || 99, quantity + 1))}
                  disabled={isOutOfStock || quantity >= (props.product.stock || 99)}
                >
                  <Icon name="plus" size={16} />
                </Button>
              </Row>
            </Stack>

            <Button
              variant="primary"
              size="lg"
              fullWidth={false}
              style={{ minWidth: '240px' }}
              leftIcon={<Icon name="shopping-cart" />}
              onClick={handleAddToCart}
              disabled={isOutOfStock}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

