// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const formatChatTime = (ts?: string) => {
  if (!ts) return '';
  try {
    return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return ts;
  }
};

export default function Component(props: Props) {
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const message = useStream<StreamMessage>('message');
  const typing = useStream<StreamTyping>('typing');

  const [allMessages, setAllMessages] = useState<StreamMessage[]>(props.messages);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [allMessages, typing.latest]);

  const handleSend = useCallback(() => {
    if (!inputText.trim()) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: inputText, timestamp });
    setAllMessages((prev) => [...prev, { sender: props.currentUser, text: inputText, timestamp }]);
    setInputText('');
  }, [inputText, props.currentUser, sendMessage]);

  const activeTyping = useMemo(() => {
    if (typing.latest?.active && typing.latest.sender !== props.currentUser) {
      return typing.latest.sender;
    }
    return null;
  }, [typing.latest, props.currentUser]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)" style={{ height: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Card padding={0} shadow="md" style={{ flex: 1, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        {/* Header */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderBottom: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Row align="center" justify="between">
            <Stack gap="var(--ggui-spacing-1)" aria-live="polite">
              <Heading level={4}>{props.title}</Heading>
              {activeTyping && (
                <Text variant="caption" color="var(--ggui-color-primary-600)" style={{ animation: 'ggui-pulse 2s infinite' }}>
                  {activeTyping} is typing...
                </Text>
              )}
            </Stack>
            <Badge variant="secondary" size="lg">{props.participantCount} participants</Badge>
          </Row>
        </Box>

        {/* Message List */}
        <Box role="log" aria-live="polite" style={{ flex: 1, overflowY: 'auto' }} padding="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-4)">
            {allMessages.map((msg, idx) => {
              const isOwn = msg.sender === props.currentUser;
              const prevMsg = allMessages[idx - 1];
              const isGrouped = prevMsg && prevMsg.sender === msg.sender;

              return (
                <Stack key={`${msg.timestamp}-${idx}`} align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
                  {!isGrouped && (
                    <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                      {msg.sender}
                    </Text>
                  )}
                  <Box
                    paddingX="var(--ggui-spacing-4)"
                    paddingY="var(--ggui-spacing-2)"
                    borderRadius="var(--ggui-shape-radius-lg)"
                    background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                    style={{ maxWidth: '80%', alignSelf: isOwn ? 'flex-end' : 'flex-start' }}
                  >
                    <Text color={isOwn ? 'white' : 'var(--ggui-color-onSurface)'}>
                      {msg.text}
                    </Text>
                  </Box>
                  <Text variant="caption" size="xs" color="var(--ggui-color-onSurfaceVariant)">
                    {formatChatTime(msg.timestamp)}
                  </Text>
                </Stack>
              );
            })}
            <div ref={scrollRef} />
          </Stack>
        </Box>

        {/* Input Area */}
        <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-surface)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <TextArea
                label="Message"
                placeholder="Type a message..."
                value={inputText}
                onChange={setInputText}
                rows={1}
                autoResize
                onKeyDown={(e: React.KeyboardEvent) => {
                  if (e.key === 'Enter' && !e.shiftKey) {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button
              as={Clickable}
              onClick={handleSend}
              disabled={!inputText.trim()}
              variant="primary"
            >
              Send
            </Button>
          </Row>
        </Box>
      </Card>
    </Container>
  );
}

