}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Helper for individual stock cards to handle flash logic and formatting
function StockCardItem(props: { stock: { symbol?: string; name?: string; price?: number; change?: number; changePercent?: number } }) {
  const [isFlashing, setIsFlashing] = useState(false);
  const prevPrice = useRef(props.stock.price);

  useEffect(() => {
    if (props.stock.price !== prevPrice.current) {
      setIsFlashing(true);
      const timer = setTimeout(() => setIsFlashing(false), 600);
      prevPrice.current = props.stock.price;
      return () => clearTimeout(timer);
    }
  }, [props.stock.price]);

  const isPositive = (props.stock.change ?? 0) >= 0;
  const statusColor = isPositive ? 'var(--ggui-color-success)' : 'var(--ggui-color-error)';
  const statusBg = isPositive ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)';
  const trendIcon = isPositive ? 'trending-up' : 'trending-down';
  const trendArrow = isPositive ? '▲' : '▼';

  return (
    <Card
      padding="var(--ggui-spacing-4)"
      shadow="sm"
      radius="lg"
      style={{
        border: `1px solid ${statusColor}`,
        backgroundColor: isFlashing ? statusBg : 'var(--ggui-color-surface)',
        transition: 'all 0.3s ease-in-out',
        height: '100%',
      }}
    >
      <Stack gap="var(--ggui-spacing-3)">
        <Row justify="between" align="start">
          <Stack gap={0}>
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.stock.symbol}</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" truncate>
              {props.stock.name}
            </Text>
          </Stack>
          <Icon name={trendIcon} color={statusColor} size={20} />
        </Row>

        <Stack gap="var(--ggui-spacing-1)">
          <Text size="3xl" weight="bold" color="var(--ggui-color-onSurface)" aria-live="polite">
            ${(props.stock.price ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
          </Text>
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Badge variant={isPositive ? 'success' : 'error'} size="sm">
              {trendArrow} {(props.stock.changePercent ?? 0).toFixed(2)}%
            </Badge>
            <Text variant="bodySmall" weight="medium" color={statusColor}>
              {isPositive ? '+' : ''}{(props.stock.change ?? 0).toFixed(2)}
            </Text>
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

export default function Component(props: Props) {
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate');
  const marketStatus = useStream<StreamMarketStatus>('marketStatus');

  const [stocks, setStocks] = useState(props.stocks);
  const [currentTime, setCurrentTime] = useState(new Date().toLocaleTimeString());

  // Update stocks when a price update arrives via stream
  useEffect(() => {
    if (priceUpdate.latest?.symbol) {
      setStocks(prev => prev.map(s => {
        if (s.symbol === priceUpdate.latest?.symbol) {
          return { ...s, ...priceUpdate.latest };
        }
        return s;
      }));
    }
  }, [priceUpdate.latest]);

  // Keep the clock running for "Last Updated" visual if no stream timestamp exists
  useEffect(() => {
    const timer = setInterval(() => {
      setCurrentTime(new Date().toLocaleTimeString());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const lastUpdated = marketStatus.latest?.timestamp
    ? new Date(marketStatus.latest.timestamp).toLocaleTimeString()
    : currentTime;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header Section */}
        <Row justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1}>Market Watch</Heading>
            <Row gap="var(--ggui-spacing-2)" align="center">
              <Box
                style={{ width: 8, height: 8 }}
                borderRadius="50%"
                background={marketStatus.latest?.status === "open" ? "var(--ggui-color-success)" : "var(--ggui-color-outline)"}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite">
                Market is {marketStatus.latest?.status || "Active"} • Last Updated: {lastUpdated}
              </Text>
            </Row>
          </Stack>

          {marketStatus.latest?.status && (
            <Badge variant={marketStatus.latest.status === "open" ? "success" : "warning"}>
              {marketStatus.latest.status.toUpperCase()}
            </Badge>
          )}
        </Row>

        {/* Stock Grid */}
        <CardGrid columns={{ sm: 1, md: 3, lg: 3 }} gap={24}>
          {stocks.map((stock) => (
            <Box key={stock.symbol} as={Hoverable} hoverStyle={{ transform: "translateY(-4px)", transition: "transform 0.2s ease" }}>
              <StockCardItem stock={stock} />
            </Box>
          ))}
        </CardGrid>

        {/* Footer/Meta information */}
        <Divider margin="var(--ggui-spacing-4)" />
        <Row justify="center">
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Data provided by real-time market stream. Prices are delayed by up to 0 seconds.
          </Text>
        </Row>
      </Stack>
    </Container>
  );
}

