// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Helper for summarizing data in Step 3
function SummaryItem(props: { label: string; value: React.ReactNode }) {
  return (
    <Box paddingY="var(--ggui-spacing-2)">
      <Row justify="between" align="center">
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">{props.label}</Text>
        <Text weight="medium">{props.value}</Text>
      </Row>
    </Box>
  );
}

export default function Component(props: Props) {
  // Step management
  const [step, setStep] = useState(1);

  // Form State initialized from props.initialProfile
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || (props.avatarOptions && props.avatarOptions[0]) || '👤',
    role: props.initialProfile?.role || (props.roleOptions && props.roleOptions[0]) || '',
    emailNotifications: props.initialProfile?.emailNotifications !== undefined ? props.initialProfile.emailNotifications : true,
    theme: props.initialProfile?.theme || 'light'
  });

  // Action hook
  const complete = useAction<ActionCompletePayload>('complete');

  // Validation logic
  const isEmailValid = useMemo(() => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  }, [formData.email]);

  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid && !!formData.avatar;
  const isStep2Valid = !!formData.role;

  // Handlers
  const handleNext = useCallback(() => {
    setStep(s => Math.min(s + 1, 3));
  }, []);

  const handleBack = useCallback(() => {
    setStep(s => Math.max(s - 1, 1));
  }, []);

  const handleComplete = useCallback(() => {
    complete({ ...formData });
  }, [complete, formData]);

  const updateField = (field: keyof typeof formData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // Transform roles for Select primitive
  const roleOptionsList = useMemo(() => {
    return (props.roleOptions || []).map(role => ({ value: role, label: role }));
  }, [props.roleOptions]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-10)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header & Progress Indicator */}
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="end">
            <Stack gap="var(--ggui-spacing-1)">
              <Text variant="overline" color="var(--ggui-color-primary-600)">Onboarding</Text>
              <Heading level={2}>
                {step === 1 && 'Profile Setup'}
                {step === 2 && 'Preferences'}
                {step === 3 && 'Review & Confirm'}
              </Heading>
            </Stack>
            <Text variant="caption" weight="bold">Step {step} of 3</Text>
          </Row>
          <Progress value={(step / 3) * 100} size="md" variant="default" />
        </Stack>

        <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
          {/* STEP 1: Profile Setup */}
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Input
                label="Full Name"
                placeholder="Enter your name"
                value={formData.name}
                onChange={(val) => updateField('name', val)}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="you@example.com"
                value={formData.email}
                onChange={(val) => updateField('email', val)}
                error={formData.email && !isEmailValid ? 'Please enter a valid email' : undefined}
                required
              />
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Choose Avatar</Text>
                <Row gap="var(--ggui-spacing-4)">
                  {(props.avatarOptions || []).slice(0, 4).map((emoji) => (
                    <Box
                      key={emoji}
                      as={Clickable}
                      aria-label={`Select ${emoji} avatar`}
                      onClick={() => updateField('avatar', emoji)}
                      padding="var(--ggui-spacing-4)"
                      borderRadius="var(--ggui-shape-radius-lg)"
                      background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'}
                      style={{
                        border: `2px solid ${formData.avatar === emoji ? 'var(--ggui-color-primary-600)' : 'transparent'}`,
                        transition: 'all 0.2s ease-in-out'
                      }}
                    >
                      <Text size="4xl">{emoji}</Text>
                    </Box>
                  ))}
                </Row>
              </Stack>
            </Stack>
          )}

          {/* STEP 2: Preferences */}
          {step === 2 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Select
                label="Your Role"
                placeholder="Select your role"
                options={roleOptionsList}
                value={formData.role}
                onChange={(val) => updateField('role', val)}
                required
              />
              <Divider margin="var(--ggui-spacing-2)" />
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text weight="medium">Email Notifications</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Stay updated with the latest activity</Text>
                </Stack>
                <Toggle
                  label={formData.emailNotifications ? 'On' : 'Off'}
                  checked={formData.emailNotifications}
                  onChange={(val) => updateField('emailNotifications', val)}
                />
              </Row>
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Text weight="medium">Appearance</Text>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">Choose your preferred theme</Text>
                </Stack>
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <Icon name="sun" size={16} color={formData.theme === 'light' ? 'var(--ggui-color-warning-600)' : 'var(--ggui-color-onSurfaceVariant)'} />
                  <Toggle
                    label={formData.theme === 'light' ? 'Light' : 'Dark'}
                    checked={formData.theme === 'dark'}
                    onChange={(checked) => updateField('theme', checked ? 'dark' : 'light')}
                  />
                  <Icon name="moon" size={16} color={formData.theme === 'dark' ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-onSurfaceVariant)'} />
                </Row>
              </Row>
            </Stack>
          )}

          {/* STEP 3: Review */}
          {step === 3 && (
            <Stack gap="var(--ggui-spacing-6)">
              <Box padding="var(--ggui-spacing-4)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-lg)">
                <Row gap="var(--ggui-spacing-6)" align="center">
                  <Box padding="var(--ggui-spacing-2)" background="var(--ggui-color-surface)" borderRadius="var(--ggui-shape-radius-full)" style={{ boxShadow: 'var(--ggui-shape-shadow-sm)' }}>
                    <Text size="4xl">{formData.avatar}</Text>
                  </Box>
                  <Stack gap="var(--ggui-spacing-1)">
                    <Heading level={4}>{formData.name}</Heading>
                    <Text color="var(--ggui-color-primary-700)">{formData.role}</Text>
                  </Stack>
                </Row>
              </Box>

              <Stack gap="var(--ggui-spacing-1)">
                <SummaryItem label="Email" value={formData.email} />
                <Divider margin="var(--ggui-spacing-1)" />
                <SummaryItem label="Notifications" value={formData.emailNotifications ? 'Enabled' : 'Disabled'} />
                <Divider margin="var(--ggui-spacing-1)" />
                <SummaryItem label="Theme" value={formData.theme === 'dark' ? 'Dark Mode' : 'Light Mode'} />
              </Stack>
            </Stack>
          )}
        </Card>

        {/* Navigation Buttons */}
        <Row justify="between" align="center">
          {step > 1 ? (
            <Button as={Clickable} variant="outline" onClick={handleBack} leftIcon={<Icon name="arrow-left" size={18} />}>
              Go Back
            </Button>
          ) : <Spacer size={1} />}

          {step < 3 ? (
            <Button
              as={Clickable}
              variant="primary"
              onClick={handleNext}
              disabled={step === 1 ? !isStep1Valid : !isStep2Valid}
              rightIcon={<Icon name="arrow-right" size={18} />}
            >
              Continue
            </Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleComplete} leftIcon={<Icon name="check" size={18} />}>
              Complete Setup
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
